This example demonstrated that `connectx` also supports AF_INET6 socket.


```C
#include <errno.h>
#include <stdio.h>
#include <unistd.h>
#include <netinet/tcp.h>
#include <netinet/in.h>
#include <arpa/inet.h>
#include <sys/socket.h>
#include <netdb.h>

int main(int argc, char **argv) {
  
  struct addrinfo *server;
  int result = getaddrinfo("::1", "80", 0, &server);
  if (result != 0) {
      printf("getaddrinfo result: %i", result);
  }
  int s = socket(server->ai_family, SOCK_STREAM, IPPROTO_TCP);
  if (s < 0)
  {
    perror("socket");
    return 1;
  }
  sa_endpoints_t endpoints;
  endpoints.sae_dstaddr = server->ai_addr;
  endpoints.sae_dstaddrlen = server->ai_addrlen;

  int rc = connectx(s, &endpoints, SAE_ASSOCID_ANY, CONNECT_RESUME_ON_READ_WRITE | CONNECT_DATA_IDEMPOTENT, NULL, 0, NULL, NULL);
  if (rc < 0)
  {
    perror("connectx");
    return 1;
  }
  char buf[1024];
  rc = write(s, buf, 1024);
  if (rc < 0)
  {
    perror("write");
    return 1;
  }
  close(s);
  return 0;
}
```

