It's not just operators, it's method overloads in general:

```C++
#include <iostream>
#include <pybind11/pybind11.h>

namespace py = pybind11;

class A {
public:
    virtual int get() { return 1; }
    virtual int get(int i) { return 2 + i; }
};
class B : public A {
public:
    int get() override { return 10; }
};

PYBIND11_PLUGIN(op_inh) {
    py::module m("op_inh");
    py::class_<A>(m, "A")
        .def("get", py::overload_cast<>(&A::get))
        .def("get", py::overload_cast<int>(&A::get))
        ;
    py::class_<B, A>(m, "B")
        .def(py::init<>())
        .def("get", py::overload_cast<>(&B::get))
        ;

    return m.ptr();
}
```

